using System.Diagnostics;using BgCommon.Script.Runtime.Utilities;namespace BgCommon.Script.Runtime.DotNet;/// <summary>/// .NET 命令行运行器，用于执行外部进程及命令./// </summary>public class DotNetCliRunner{    /// <summary>    /// 执行命令行命令并返回标准输出结果.    /// </summary>    /// <param name="fileName"> 要运行的应用程序或文件的名称或路径. </param>    /// <param name="arguments"> 启动进程时要使用的命令行参数. </param>    /// <returns> 进程执行后的标准输出字符串. </returns>    /// <exception cref="ArgumentNullException"> 当 fileName 或 arguments 为空时抛出. </exception>    /// <exception cref="Exception"> 当进程启动失败时抛出. </exception>    public string ExecuteCommand(string fileName, string arguments)    {        // 验证方法参数.        ArgumentNullException.ThrowIfNull(fileName, nameof(fileName));        ArgumentNullException.ThrowIfNull(arguments, nameof(arguments));        // 配置进程启动信息.        ProcessStartInfo startInfo = new ProcessStartInfo        {            FileName = fileName,            Arguments = arguments,            UseShellExecute = false,            RedirectStandardOutput = true,            CreateNoWindow = true,            WindowStyle = ProcessWindowStyle.Hidden,        }.CopyCurrentEnvironmentVariables();        // 启动进程.        using Process? cliProcess = Process.Start(startInfo);        // 检查进程是否成功启动.        if (cliProcess == null)        {            throw new Exception($"Failed to start process: {fileName}");        }        // 读取标准输出流内容.        string commandOutput = cliProcess.StandardOutput.ReadToEnd();        // 等待进程执行完毕.        cliProcess.WaitForExit();        return commandOutput;    }}